```typescript
const lookup = state.toolLookup.get(toolName);
if (!lookup) { return { content: [...], isError: true }; }
// ...
if (!isToolEnabled(state, toolName)) { return { content: [...], isError: true }; }
```

Extract into:
```typescript
export interface ToolCallableResult {
  ok: boolean;
  pluginName?: string;
  toolName?: string;
  error?: string;
}

export const checkToolCallable = (state: ServerState, prefixedToolName: string): ToolCallableResult => {
  const lookup = state.toolLookup.get(prefixedToolName);
  if (!lookup) return { ok: false, error: `Tool ${prefixedToolName} not found` };
  if (!isToolEnabled(state, prefixedToolName)) return { ok: false, error: `Tool ${prefixedToolName} is disabled` };
  return { ok: true, pluginName: lookup.pluginName, toolName: lookup.toolName };
};
```

Then in the handler, replace the inline checks with `const check = checkToolCallable(state, toolName); if (!check.ok) { return { content: [{ type: 'text', text: check.error }], isError: true }; }`

Add tests in mcp-setup.test.ts. To set up toolLookup entries, call `rebuildToolLookups(state)` after adding plugins to `state.plugins`.

File: e2e/side-panel-plugin-toggle.e2e.ts. Follow the pattern of the existing 'toggling a tool sends config.setToolEnabled and MCP server updates state' test (line 123-236) but add the tool dispatch verification.

Key imports from fixtures.ts: `test, expect, startMcpServer, startTestServer, createMcpClient, cleanupTestConfigDir, writeTestConfig, readPluginToolNames, launchExtensionContext, E2E_TEST_PLUGIN_DIR`.
